index d824c40c401d..f45f726f2474 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -9774,6 +9774,9 @@ class BoUpSLP::ShuffleCostEstimator : public BaseShuffleAnalysis {
       TTI::ShuffleKind ShuffleKind = TTI::SK_PermuteSingleSrc;
       int FirstRegId = -1;
       Indices.assign(1, OffsetReg0);
+      // Ensure OffsetReg0 satisfies the extract subvector bounds
+      if ((OffsetReg0 + EltsPerVector) > alignTo(NumElts, EltsPerVector))
+        return std::nullopt;
       for (auto [Pos, I] : enumerate(Mask)) {
         if (I == PoisonMaskElem)
           continue;
@@ -9798,9 +9801,13 @@ class BoUpSLP::ShuffleCostEstimator : public BaseShuffleAnalysis {
                                   ((I - OffsetReg0) % NumElts) / EltsPerVector;
                       if (RegId == FirstRegId)
                         return S;
+            // Ensure the index satisfies the extract subvector bounds
+            if ((OffsetReg1 % NumElts + EltsPerVector) <= alignTo(NumElts, EltsPerVector))
                       return std::min(S, I);
                     }),
                 EltsPerVector);
+            // Ensure the index satisfies the extract subvector bounds
+            if ((OffsetReg1 % NumElts + EltsPerVector) <= alignTo(NumElts, EltsPerVector))
             Indices.push_back(OffsetReg1 % NumElts);
           }
           Idx = I - OffsetReg1;
@@ -9840,6 +9847,13 @@ class BoUpSLP::ShuffleCostEstimator : public BaseShuffleAnalysis {
             ::getShuffleCost(TTI, *RegShuffleKind,
                              getWidenedType(ScalarTy, EltsPerVector), SubMask);
       }
+      // Filter out invalid indices that would violate the assertion
+      SmallVector<unsigned, 2> ValidIndices;
+      for (unsigned Idx : Indices) {
+        if ((Idx + EltsPerVector) <= alignTo(NumElts, EltsPerVector))
+          ValidIndices.push_back(Idx);
+      }
+      Indices = std::move(ValidIndices);
       for (unsigned Idx : Indices) {
         assert((Idx + EltsPerVector) <= alignTo(NumElts, EltsPerVector) &&
                "SK_ExtractSubvector index out of range");

